// Junta las 4 búsquedas, saca solo los NUEVOS, rankea y arma un email lindo.
const EXCL = ['clearance','principal','vice president',' vp ','head of engineering','staff engineer'];
const KW = ['automation','automat','ai ','artificial','partnership','sales','account','growth','data','analyst','no-code','nocode','zapier','make','workflow','crm','integration'];

// 1) Juntar todos los empleos de las 4 búsquedas
const all = [];
for (const item of $input.all()) {
  const jobs = (item.json && item.json.jobs) || [];
  for (const j of jobs) all.push(j);
}

// 2) Memoria de lo ya avisado (persiste entre ejecuciones)
const sd = $getWorkflowStaticData('global');
sd.seen = sd.seen || [];
const seen = new Set(sd.seen);

// 3) Deduplicar, filtrar ruido, quedarse con los NUEVOS
const byUrl = new Set();
const fresh = [];
for (const j of all) {
  if (!j.url || byUrl.has(j.url)) continue;
  byUrl.add(j.url);
  const t = (j.title || '').toLowerCase();
  if (EXCL.some(e => t.includes(e))) continue;
  if (seen.has(j.url)) continue;
  j._score = KW.reduce((s, k) => s + (t.includes(k) ? 1 : 0), 0);
  fresh.push(j);
}

// 4) Rankear por fit y fecha
fresh.sort((a, b) => (b._score - a._score) || (new Date(b.publication_date) - new Date(a.publication_date)));
const top = fresh.slice(0, 12);

// 5) Marcar como vistos (para no repetir la próxima)
for (const j of top) sd.seen.push(j.url);
if (sd.seen.length > 800) sd.seen = sd.seen.slice(-800);

if (!top.length) return [{ json: { count: 0, html: '' } }];

// 6) Armar email HTML
let rows = '';
for (const j of top) {
  const loc = j.candidate_required_location || 'Remoto';
  const sal = j.salary ? ` · <span style=\"color:#28a06a\">${j.salary}</span>` : '';
  const fire = j._score >= 3 ? '\uD83D\uDD25 ' : '';
  rows += `<tr><td style=\"padding:11px 0;border-bottom:1px solid #eee\"><a href=\"${j.url}\" style=\"color:#7c5cff;font-weight:bold;text-decoration:none;font-size:15px\">${fire}${j.title}</a><br><span style=\"color:#555;font-size:13px\">${j.company_name} · ${loc}${sal}</span></td></tr>`;
}
const html = `<div style=\"font-family:Arial,Helvetica,sans-serif;max-width:620px;margin:0 auto\"><h2 style=\"color:#7c5cff;margin-bottom:4px\">\uD83C\uDFAF Cazador de Empleos</h2><p style=\"color:#555;margin-top:0\">${top.length} roles remotos NUEVOS para tu perfil (IA Automation / Data / Partnerships / Sales). Toc\u00e1 el t\u00edtulo para aplicar:</p><table style=\"width:100%;border-collapse:collapse\">${rows}</table><p style=\"color:#aaa;font-size:12px;margin-top:18px\">Automatizado con n8n \u00b7 Lleyton IA Automation</p></div>`;

return [{ json: { count: top.length, html } }];
